   323→                        Coredump.getInstance().onCompleted((String)msg.obj);
   324→                    } else {
   325→                        Coredump.getInstance().onCompleted(null);
   326→                    }
   327→                    // waitCompleted
   328→                    Coredump.getInstance().notifyCompleted();
   329→                } break;
   330→            }
   331→        }
   332→    }
