   123→bool Opencore::IsEnabled() {
   124→    bool installed = false;
   125→    pthread_mutex_lock(&g_switch_lock);
   126→    installed = handlers_installed;
   127→    pthread_mutex_unlock(&g_switch_lock);
   128→    return installed;
   129→}
